"use strict";const ERROR_PLATFORM_NOT_SUPPORT=new Error("platform not support"),ERROR_NO_INSTALLATIONS_FOUND=new Error("no chrome installations found");function findChrome(r=!1){const{platform:e}=process;let n=[];switch(e){case"win32":n=require("./win32")(r);break;case"darwin":n=require("./darwin")(r);break;case"linux":n=require("./linux")(r);break;default:throw ERROR_PLATFORM_NOT_SUPPORT}if(n.length)return n[0];throw ERROR_NO_INSTALLATIONS_FOUND}module.exports=findChrome;